CREATE TABLE IF NOT EXISTS public.autonomous_agent_scans (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), scan_type text NOT NULL DEFAULT 'scheduled', status text NOT NULL DEFAULT 'completed', total_properties_scanned integer DEFAULT 0, total_alerts_created integer DEFAULT 0, total_users_notified integer DEFAULT 0, summary jsonb DEFAULT '{}', duration_ms integer DEFAULT 0, error_message text, created_at timestamptz NOT NULL DEFAULT now()); ALTER TABLE public.autonomous_agent_scans ENABLE ROW LEVEL SECURITY; CREATE POLICY "Authenticated users can read scan logs" ON public.autonomous_agent_scans FOR SELECT TO authenticated USING (true); CREATE INDEX idx_agent_scans_created_at ON public.autonomous_agent_scans(created_at DESC);